37	    /**
38	     * Helper function to construct prompts from input texts
39	     * @param {string|string[]} text
40	     * @returns {string[]}
41	     */
42	    construct_prompts(text) {
43	        if (typeof text === 'string') {
44	            text = [text];
45	        }
46	
47	        const prompts = [];
48	        for (const t of text) {
49	            // 1. fixed task prompts without additional inputs
50	            if (this.task_prompts_without_inputs.has(t)) {
51	                prompts.push(this.task_prompts_without_inputs.get(t));
52	            }
53	            // 2. task prompts with additional inputs 
54	            else {
55	                for (const [task, prompt] of this.task_prompts_with_input) {
56	                    if (t.includes(task)) {
57	                        prompts.push(prompt.replaceAll('{input}', t).replaceAll(task, ''));
58	                        break;
59	                    }
60	                }
61	
62	                // 3. default prompt
63	                if (prompts.length !== text.length) {
