83	        let final_answer;
84	        switch (task_answer_post_processing_type) {
85	            case 'pure_text':
86	                final_answer = text;
87	                break;
88	
89	            case 'description_with_bboxes':
90	            case 'bboxes':
91	            case 'phrase_grounding':
92	            case 'ocr':
93	                const key = task_answer_post_processing_type === 'ocr' ? 'quad_boxes' : 'bboxes';
94	                const matches = text.matchAll(this.regexes[key]);
95	                const labels = [];
96	                const items = [];
97	                for (const [_, label, ...locations] of matches) {
98	                    // Push new label, or duplicate the last label
99	                    labels.push(label ? label.trim() : labels.at(-1) ?? '');
100	                    items.push(locations.map((x, i) =>
101	                        // NOTE: Add 0.5 to use the center position of the bin as the coordinate.
102	                        (Number(x) + 0.5) / this.size_per_bin * image_size[i % 2])
103	                    );
104	                }
105	                final_answer = { labels, [key]: items };
106	                break;
107	
108	            default:
109	                throw new Error(`Task "${task}" (of type "${task_answer_post_processing_type}") not yet implemented.`);
110	        }
111	
112	        return { [task]: final_answer }
113	    }
