116	    // `images` is required, `text` is optional
117	    async _call(images, text=null, kwargs = {}) {
118	
119	        if (!images && !text){
120	            throw new Error('Either text or images must be provided');
121	        }
122	
123	        const image_inputs = await this.image_processor(images, kwargs);
124	        const text_inputs = text ? this.tokenizer(this.construct_prompts(text), kwargs) : {};
125	
126	        return {
127	            ...image_inputs,
128	            ...text_inputs,
129	        }
